const raw = $input.first().json;
const msg = raw.message || raw.edited_message || raw.channel_post || {};
const chatId = msg.chat?.id;
const userId = msg.from?.id;
const userName = [msg.from?.first_name, msg.from?.last_name].filter(Boolean).join(' ') || msg.from?.username || 'unknown';
const text = (msg.text || msg.caption || '').trim();
const ownerId = Number($env.OWNER_TELEGRAM_ID || '8134595837');
if (!chatId || !userId) return [];
return [{
  json: {
    chatId,
    userId,
    userName,
    text,
    authorized: Number(userId) === ownerId,
    isReset: /^\/reset\b/i.test(text),
    receivedAt: new Date().toISOString()
  }
}];

const item = $input.first().json;
const staticData = $getWorkflowStaticData('global');
staticData.memory ||= {};
delete staticData.memory[String(item.userId)];
return [{ json: { chatId: item.chatId, answer: 'Память очищена. Погнали заново.' } }];

const item = $input.first().json;
const text = item.text || '';
const lower = text.toLowerCase();
const env = (name, fallback) => $env[name] || fallback;
const models = {
  fast: env('OPENROUTER_MODEL_FAST', 'deepseek/deepseek-chat'),
  pro: env('OPENROUTER_MODEL_PRO', 'deepseek/deepseek-chat'),
  reasoning: env('OPENROUTER_MODEL_REASONING', 'deepseek/deepseek-r1'),
  coder: env('OPENROUTER_MODEL_CODER', 'deepseek/deepseek-coder'),
  fallback: env('OPENROUTER_MODEL_FALLBACK', 'deepseek/deepseek-chat')
};
let mode = 'automind_pro';
let model = models.pro;
let temperature = 0.35;
let max_tokens = 2200;
const techWords = ['код', 'n8n', 'api', 'json', 'debug', 'ошибка', 'workflow', 'воркфлоу', 'docker', 'сервер', 'бот сломался', 'интеграция'];
const salesWords = ['продажи', 'скрипт', 'возражение', 'лид', 'клиент', 'демо', 'предоплата', 'кп', 'партнер', 'партнёр', 'оффер'];
const hardWords = ['стратегия', 'план', 'архитектура', 'финансы', 'найм', 'юрид', 'риски', '20 млн', 'масштаб', 'инвестиции', 'автопилот'];
const riskWords = ['договор', 'налог', 'ип', 'самозанят', '152-фз', 'безопасность', 'пароль', 'доступ', 'бэкап', 'репутация'];
if (/^\/(fast|flash)\b/i.test(text) || (text.length < 140 && !hardWords.some(w => lower.includes(w)))) {
  mode = 'fast';
  model = models.fast;
  temperature = 0.25;
  max_tokens = 1000;
}
if (/^\/(tech|code|n8n)\b/i.test(text) || techWords.some(w => lower.includes(w))) {
  mode = 'tech_builder';
  model = models.coder;
  temperature = 0.2;
  max_tokens = 2800;
}
if (/^\/(pro|deep|deepseek|think|plan)\b/i.test(text) || hardWords.some(w => lower.includes(w))) {
  mode = 'deep_strategy';
  model = models.reasoning;
  temperature = 0.3;
  max_tokens = 3600;
}
if (/^\/(sales|money)\b/i.test(text) || salesWords.some(w => lower.includes(w))) {
  mode = 'sales_money';
  model = models.pro;
  temperature = 0.35;
  max_tokens = 2400;
}
if (/^\/(risk|legal|safe)\b/i.test(text) || riskWords.some(w => lower.includes(w))) {
  mode = 'risk_control';
  model = models.reasoning;
  temperature = 0.25;
  max_tokens = 2600;
}
const cleanText = text.replace(/^\/(fast|flash|tech|code|n8n|pro|deep|deepseek|think|plan|sales|money|risk|legal|safe)\s*/i, '').trim() || text;
const systemPrompt = `Ты — личный AI-ассистент Ивана: старший кент-наставник. Ты старше, спокойнее и опытнее. Говоришь по-русски живо, прямо, понятно, без канцелярита, без воды и без кринжа.

Главное: помогай Ивану выигрывать в реальных задачах: AutoMind, продажи, найм, n8n, Telegram-боты, сайты, AI, деньги, юридические риски, здоровье, учёба, команда и переговоры. Думай как топ-1% спец в нужной сфере, но объясняй простым языком.

AutoMind: система заявок для МСБ: сайт/лендинг → Telegram-бот → CRM → напоминания → аналитика → AI → поддержка. Бот как модуль до 50к. Большой чек через систему заявок 120–300к+ и поддержку 10–30к/мес. Цель агрессивная: идти к 20 млн ₽/мес через Revenue OS, Partner Engine, Demo Factory, Deal Desk, Delivery OS, Support Desk, Risk & Control OS, команду и автоматизации.

Правила:
1. Сначала главный вывод в 1–3 строках.
2. Потом конкретный план, таблица или чеклист.
3. В конце — самый первый шаг.
4. Отделяй факты от предположений. Если не уверен — скажи, что надо проверить.
5. Не обещай гарантий и не выдумывай цифры/кейсы. Давай вилки, условия и риски.
6. Сначала деньги, продажи, снижение рутины и рисков; потом красота.
7. Если идея опасная — скажи прямо и дай безопасную альтернативу.
8. Не советуй серый спам, обход банов, незаконные схемы, хранение секретов в чатах, обман клиентов или фейковые кейсы.
9. По налогам/договорам/несовершеннолетию/152-ФЗ — дай чеклист и напомни проверить со взрослым, юристом или бухгалтером.
10. Если задача большая — разбей на сейчас / сегодня / 3 дня / 7 дней / месяц.

Режимы: fast — коротко; sales_money — продажи; tech_builder — n8n/API/код; deep_strategy — стратегия/найм/финансы; risk_control — юридика/безопасность/репутация; life_coach — дисциплина/энергия.

Стиль: свой человек, но умный и жёсткий к реальности. Не сюсюкай. Держи фокус на результате.`;
const staticData = $getWorkflowStaticData('global');
staticData.memory ||= {};
const key = String(item.userId);
const memory = staticData.memory[key] || [];
const userContent = `Режим: ${mode}\nМодель: ${model}\nВремя: ${item.receivedAt}\n\nЗадача от Ивана:\n${cleanText}`;
const messages = [
  { role: 'system', content: systemPrompt },
  ...memory.slice(-8),
  { role: 'user', content: userContent }
];
return [{
  json: {
    ...item,
    mode,
    model,
    fallbackModel: models.fallback,
    cleanText,
    temperature,
    max_tokens,
    messages,
    openRouterBody: { model, messages, temperature, max_tokens }
  }
}];

const context = $input.first().json;
const apiKey = $env.OPENROUTER_API_KEY;
if (!apiKey) {
  throw new Error('OPENROUTER_API_KEY is not set');
}
const url = 'https://openrouter.ai/api/v1/chat/completions';
const timeoutMs = Number($env.OPENROUTER_TIMEOUT_MS || 15000);
const maxAttempts = Number($env.OPENROUTER_MAX_ATTEMPTS || 3);
const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));
async function callOpenRouter(body, attempt) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const res = await fetch(url, {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${apiKey}`,
        'Content-Type': 'application/json',
        'HTTP-Referer': $env.OPENROUTER_SITE_URL || 'https://automind.local',
        'X-Title': 'AutoMind Universal AI Assistant'
      },
      body: JSON.stringify(body),
      signal: controller.signal
    });
    const raw = await res.text();
    let parsed;
    try { parsed = raw ? JSON.parse(raw) : {}; } catch (e) { parsed = { raw }; }
    if (!res.ok) {
      const msg = parsed?.error?.message || parsed?.message || raw || `HTTP ${res.status}`;
      const err = new Error(msg);
      err.status = res.status;
      err.payload = parsed;
      throw err;
    }
    return parsed;
  } finally {
    clearTimeout(timer);
  }
}
let lastError = null;
let usedModel = context.model;
let response = null;
for (let attempt = 1; attempt <= maxAttempts; attempt++) {
  const useFallback = attempt === maxAttempts && context.fallbackModel && context.fallbackModel !== context.model;
  usedModel = useFallback ? context.fallbackModel : context.model;
  const body = { ...context.openRouterBody, model: usedModel };
  try {
    response = await callOpenRouter(body, attempt);
    const answer = response?.choices?.[0]?.message?.content;
    if (answer && String(answer).trim()) {
      return [{ json: { ...context, openRouterResponse: response, attempts: attempt, usedModel, fallbackUsed: useFallback } }];
    }
    lastError = new Error('Empty answer from OpenRouter');
  } catch (error) {
    lastError = error;
    if (attempt < maxAttempts) {
      await sleep(1500 * attempt);
    }
  }
}
return [{
  json: {
    ...context,
    openRouterResponse: null,
    attempts: maxAttempts,
    usedModel,
    fallbackUsed: usedModel !== context.model,
    openRouterError: lastError?.message || 'Unknown OpenRouter error',
    openRouterStatus: lastError?.status || null
  }
}];

const context = $input.first().json;
const data = context.openRouterResponse;
let answer = data?.choices?.[0]?.message?.content || '';
if (!answer) {
  answer = `OpenRouter не ответил нормально. Ошибка: ${context.openRouterError || 'пустой ответ'}.\n\nПервый шаг: проверь OPENROUTER_API_KEY, model id и баланс OpenRouter.`;
}
answer = String(answer).trim();
const warnings = [];
if (/\b(гарантированно|точно будет|100%|без риска|железно)\b/i.test(answer)) {
  warnings.push('в ответе есть слишком жёсткая гарантия — проверь условия');
}
if (/(50\+\s*(клиент|салон|проект)|уже подключено\s*50)/i.test(answer)) {
  warnings.push('соцдоказательство 50+ нельзя использовать без факта');
}
if (/(20\s*млн|миллион)/i.test(answer) && !/(если|при услов|вилка|риск|примерно|может|агрессив)/i.test(answer)) {
  warnings.push('финансовую цифру лучше считать как сценарий, а не обещание');
}
if (warnings.length) {
  answer += `\n\nПроверка реальности: ${warnings.join('; ')}.`;
}
const usage = data?.usage || {};
const totalTokens = Number(usage.total_tokens || 0);
const costPer1k = Number($env.OPENROUTER_COST_PER_1K_TOKENS || 0);
const estimatedCost = costPer1k && totalTokens ? Number(((totalTokens / 1000) * costPer1k).toFixed(6)) : 0;
const staticData = $getWorkflowStaticData('global');
staticData.memory ||= {};
staticData.usageLogs ||= [];
const key = String(context.userId);
const old = staticData.memory[key] || [];
staticData.memory[key] = [
  ...old,
  { role: 'user', content: context.cleanText || context.text },
  { role: 'assistant', content: answer }
].slice(-10);
staticData.usageLogs.push({
  ts: new Date().toISOString(),
  userId: context.userId,
  mode: context.mode,
  model: context.usedModel || context.model,
  attempts: context.attempts,
  fallbackUsed: context.fallbackUsed,
  totalTokens,
  estimatedCost
});
staticData.usageLogs = staticData.usageLogs.slice(-200);
const meta = `\n\n_режим: ${context.mode} · модель: ${context.usedModel || context.model} · попытки: ${context.attempts || 1}${context.fallbackUsed ? ' · fallback' : ''}${totalTokens ? ` · tokens: ${totalTokens}` : ''}_`;
const finalAnswer = answer + meta;
const chunks = [];
for (let i = 0; i < finalAnswer.length; i += 3800) chunks.push(finalAnswer.slice(i, i + 3800));
return chunks.map((chunk, index) => ({
  json: {
    chatId: context.chatId,
    answer: chunk,
    mode: context.mode,
    model: context.usedModel || context.model,
    part: index + 1,
    total: chunks.length
  }
}));
